use std::env;
use std::process;

fn arg_value(name: &str, default: &str) -> String {
    let args: Vec<String> = env::args().collect();
    for i in 0..args.len() {
        if args[i] == name && i + 1 < args.len() {
            return args[i + 1].clone();
        }
    }
    default.to_string()
}

fn parse_mode() -> Option<String> {
    for a in env::args() {
        if a == "synthetic" || a == "replay" || a == "batch" || a == "fuse" {
            return Some(a);
        }
    }
    None
}

fn usage() {
    eprintln!(
        "rtlsdr-mock-sim (native stub)\n\
         Modes: synthetic | replay | batch | fuse\n\
         This native binary currently emits contract-shaped JSON stubs.\n\
         Full DSP/data-path remains in TS fallback until rust port lands."
    );
}

fn json_escape(s: &str) -> String {
    s.replace('\\', "\\\\").replace('"', "\\\"")
}

fn main() {
    let mode = match parse_mode() {
        Some(m) => m,
        None => {
            usage();
            process::exit(1);
        }
    };
    let iq_rate = arg_value("--iq-rate", "2048000");
    let audio_rate = arg_value("--audio-rate", "48000");

    if mode == "synthetic" {
        let u8_out = arg_value("--u8-out", ".qa-artifacts/rtlsdr/mock.u8");
        let wav_out = arg_value("--wav-out", ".qa-artifacts/rtlsdr/mock.wav");
        println!(
            "{{\n  \"mode\": \"synthetic\",\n  \"u8Out\": \"{}\",\n  \"wavOut\": \"{}\",\n  \"iqRateHz\": {},\n  \"audioRateHz\": {},\n  \"iqSpinHintHz\": 0,\n  \"recommendedIfOffsetHz\": 0,\n  \"nativeStub\": true\n}}",
            json_escape(&u8_out),
            json_escape(&wav_out),
            iq_rate,
            audio_rate
        );
        return;
    }

    if mode == "replay" {
        let iq_file = arg_value("--iq-file", "");
        let wav_out = arg_value("--wav-out", ".qa-artifacts/rtlsdr/mock.wav");
        println!(
            "{{\n  \"mode\": \"replay\",\n  \"iqFile\": \"{}\",\n  \"wavOut\": \"{}\",\n  \"format\": \"rtl_u8\",\n  \"iqRateHz\": {},\n  \"audioRateHz\": {},\n  \"iqSpinHintHz\": 0,\n  \"recommendedIfOffsetHz\": 0,\n  \"nativeStub\": true\n}}",
            json_escape(&iq_file),
            json_escape(&wav_out),
            iq_rate,
            audio_rate
        );
        return;
    }

    if mode == "batch" {
        let capture_dir = arg_value("--capture-dir", "");
        let summary_path = arg_value(
            "--batch-summary",
            ".qa-artifacts/rtlsdr/batch-summary.json",
        );
        let wav_dir = arg_value("--batch-wav-dir", ".qa-artifacts/rtlsdr/batch-wav");
        println!(
            "{{\n  \"mode\": \"batch\",\n  \"captureDir\": \"{}\",\n  \"filesProcessed\": 0,\n  \"summaryPath\": \"{}\",\n  \"wavDir\": \"{}\",\n  \"nativeStub\": true\n}}",
            json_escape(&capture_dir),
            json_escape(&summary_path),
            json_escape(&wav_dir)
        );
        return;
    }

    let fusion_out = arg_value("--fusion-out", ".qa-artifacts/rtlsdr/fusion.json");
    println!(
        "{{\n  \"mode\": \"fuse\",\n  \"fusionOutPath\": \"{}\",\n  \"batchCaptureCount\": 0,\n  \"rtl433EventCount\": 0,\n  \"matchCount\": 0,\n  \"nativeStub\": true\n}}",
        json_escape(&fusion_out)
    );
}
